#include <chrono>

void compare_merge_to_stalin()
{

    std::vector<int> test_array = BIG_VECTOR;
    std::cout << "Using Int vector of size " << test_array.size();

    std::cout << "\nMerge sort finished in ";

       // Start timer
    auto start = std::chrono::high_resolution_clock::now();

    mergeSort(&test_array[0], 0, test_array.size()-1);

    auto end = std::chrono::high_resolution_clock::now();
    auto duration = (end - start);
    auto us = std::chrono::duration_cast<std::chrono::microseconds>(duration); // Microsecond (as int)

    std::cout << us.count() << " microseconds";
    
    test_array.clear();
    test_array = BIG_VECTOR;
    
    std::cout << "\nStalin sort finished in ";
       // Start timer
    start = std::chrono::high_resolution_clock::now();

    test_array = Stalin_Sort(test_array);

    end = std::chrono::high_resolution_clock::now();
    duration = (end - start);
    us = std::chrono::duration_cast<std::chrono::microseconds>(duration); // Microsecond (as int)

    std::cout << us.count() << " microseconds";
}










